SELECT baseline."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh", approx_percentile(baseline."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__upgrade__quartiles", approx_percentile(baseline."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE baseline."out.electricity.total.energy_consumption..kwh" != 0) AS "electricity.total.energy_consumption..kwh__upgrade__nonzero_quartiles" 
FROM (SELECT * 
FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet 
WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline 
WHERE baseline.applicability = true AND baseline.state = 'CO' GROUP BY 1 ORDER BY 1